func (m seasonTeamStandingMods) WithParentsCascading() SeasonTeamStandingMod {
	return SeasonTeamStandingModFunc(func(ctx context.Context, o *SeasonTeamStandingTemplate) {
		if isDone, _ := seasonTeamStandingWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = seasonTeamStandingWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewSeasonWithContext(ctx, SeasonMods.WithParentsCascading())
			m.WithSeason(related).Apply(ctx, o)
		}
		{

			related := o.f.NewTeamWithContext(ctx, TeamMods.WithParentsCascading())
			m.WithTeam(related).Apply(ctx, o)
		}
	})
}

